{"version":3,"file":"mine.js","sources":["pages/mine/mine.vue","C:/dv/HBuilderX/plugins/uniapp-cli-vite/uniPage:/cGFnZXMvbWluZS9taW5lLnZ1ZQ"],"sourcesContent":["<template>\r\n  <view class=\"page\">\r\n\r\n    <!-- 未登录 -->\r\n    <view v-if=\"!authState.isLoggedIn\" class=\"login-card\">\r\n      <view class=\"avatar-circle\">\r\n        <text class=\"avatar-icon\">👤</text>\r\n      </view>\r\n      <text class=\"unlogged-tip\" :style=\"{ fontSize: rpx(28) }\">未登录</text>\r\n      <button class=\"login-btn\" :style=\"{ fontSize: rpx(30) }\" @click=\"handleLogin\">\r\n        一键微信登录\r\n      </button>\r\n    </view>\r\n\r\n    <!-- 已登录 -->\r\n    <view v-else>\r\n\r\n      <!-- 个人信息头部 -->\r\n      <view class=\"profile-header\">\r\n        <button class=\"avatar-btn\" open-type=\"chooseAvatar\" @chooseavatar=\"onChooseAvatar\">\r\n          <image\r\n            v-if=\"authState.userInfo?.avatarUrl\"\r\n            class=\"avatar\"\r\n            :src=\"authState.userInfo.avatarUrl\"\r\n            mode=\"aspectFill\"\r\n          />\r\n          <view v-else class=\"avatar-circle\">\r\n            <text class=\"avatar-icon\">👤</text>\r\n          </view>\r\n        </button>\r\n        <view class=\"profile-info\">\r\n          <input\r\n            class=\"nickname-input\"\r\n            type=\"nickname\"\r\n            :value=\"authState.userInfo?.nickname || '微信用户'\"\r\n            :style=\"{ fontSize: rpx(34) }\"\r\n            placeholder=\"点击修改昵称\"\r\n            @blur=\"onNicknameBlur\"\r\n          />\r\n          <text class=\"openid-text\" :style=\"{ fontSize: rpx(22) }\">\r\n            ID: {{ authState.userInfo?.openid?.slice(0, 12) }}...\r\n          </text>\r\n        </view>\r\n      </view>\r\n\r\n      <!-- 功能菜单 -->\r\n      <view class=\"menu-group\">\r\n        <view class=\"menu-item\" @click=\"onCollect\">\r\n          <text class=\"menu-label\" :style=\"{ fontSize: rpx(28) }\">我的收藏</text>\r\n          <text class=\"menu-arrow\">›</text>\r\n        </view>\r\n        <view class=\"divider\" />\r\n        <view class=\"menu-item\" @click=\"onLanguage\">\r\n          <text class=\"menu-label\" :style=\"{ fontSize: rpx(28) }\">语言设置</text>\r\n          <text class=\"menu-arrow\">›</text>\r\n        </view>\r\n        <view class=\"divider\" />\r\n        <view class=\"menu-item\" @click=\"onElder\">\r\n          <text class=\"menu-label\" :style=\"{ fontSize: rpx(28) }\">长辈模式</text>\r\n          <text class=\"menu-arrow\">›</text>\r\n        </view>\r\n        <view class=\"divider\" />\r\n        <view class=\"menu-item\" @click=\"onAbout\">\r\n          <text class=\"menu-label\" :style=\"{ fontSize: rpx(28) }\">关于 TripMate</text>\r\n          <text class=\"menu-arrow\">›</text>\r\n        </view>\r\n      </view>\r\n\r\n      <!-- 退出登录 -->\r\n      <button class=\"logout-btn\" :style=\"{ fontSize: rpx(28) }\" @click=\"handleLogout\">\r\n        退出登录\r\n      </button>\r\n\r\n    </view>\r\n\r\n    <view class=\"tabbar-placeholder\" />\r\n    <TabBar active=\"mine\" />\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { useAuth } from '@/composables/useAuth'\r\nimport { useElder } from '@/composables/useElder'\r\nimport TabBar from '@/components/TabBar/TabBar.vue'\r\n\r\nconst { authState, login, logout, saveProfile } = useAuth()\r\nconst { rpx } = useElder()\r\n\r\nasync function handleLogin() {\r\n  try {\r\n    await login()\r\n    uni.showToast({ title: '登录成功', icon: 'success' })\r\n  } catch {\r\n    uni.showToast({ title: '登录失败，请重试', icon: 'none' })\r\n  }\r\n}\r\n\r\nfunction handleLogout() {\r\n  uni.showModal({\r\n    title: '退出登录',\r\n    content: '确认退出登录吗？',\r\n    success: (res) => {\r\n      if (res.confirm) {\r\n        logout()\r\n        uni.showToast({ title: '已退出登录', icon: 'none' })\r\n      }\r\n    }\r\n  })\r\n}\r\n\r\nasync function onChooseAvatar(e: any) {\r\n  const newAvatarUrl: string = e.detail.avatarUrl\r\n  if (!newAvatarUrl) return\r\n  try {\r\n    await saveProfile(authState.userInfo?.nickname || '', newAvatarUrl)\r\n    uni.showToast({ title: '头像已更新', icon: 'success' })\r\n  } catch {\r\n    uni.showToast({ title: '更新失败', icon: 'none' })\r\n  }\r\n}\r\n\r\nasync function onNicknameBlur(e: any) {\r\n  const newNickname: string = e.detail.value?.trim()\r\n  if (!newNickname || newNickname === authState.userInfo?.nickname) return\r\n  try {\r\n    await saveProfile(newNickname, authState.userInfo?.avatarUrl || '')\r\n    uni.showToast({ title: '昵称已更新', icon: 'success' })\r\n  } catch {\r\n    uni.showToast({ title: '更新失败', icon: 'none' })\r\n  }\r\n}\r\n\r\nfunction onCollect() {\r\n  uni.showToast({ title: '敬请期待', icon: 'none' })\r\n}\r\n\r\nfunction onLanguage() {\r\n  uni.navigateTo({ url: '/pages/language/language' })\r\n}\r\n\r\nfunction onElder() {\r\n  uni.navigateTo({ url: '/pages/elder/elder' })\r\n}\r\n\r\nfunction onAbout() {\r\n  uni.showModal({\r\n    title: '关于 TripMate',\r\n    content: 'TripMate 智能旅行助手\\n版本 1.0.0\\n\\n让旅行更简单、更美好。',\r\n    showCancel: false\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.page {\r\n  min-height: 100vh;\r\n  background-color: #f7f8fa;\r\n}\r\n\r\n/* 未登录 */\r\n.login-card {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  padding: 120rpx 32rpx 0;\r\n}\r\n\r\n.unlogged-tip {\r\n  margin-top: 24rpx;\r\n  color: #999;\r\n}\r\n\r\n.login-btn {\r\n  margin-top: 48rpx;\r\n  width: 480rpx;\r\n  background-color: #07c160;\r\n  color: #fff;\r\n  border-radius: 48rpx;\r\n  border: none;\r\n}\r\n\r\n/* 头像通用 */\r\n.avatar-circle {\r\n  width: 120rpx;\r\n  height: 120rpx;\r\n  border-radius: 60rpx;\r\n  background-color: #e0e0e0;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n}\r\n\r\n.avatar-icon {\r\n  font-size: 60rpx;\r\n}\r\n\r\n/* 已登录 — 个人信息头部 */\r\n.profile-header {\r\n  display: flex;\r\n  align-items: center;\r\n  background-color: #fff;\r\n  padding: 48rpx 32rpx;\r\n  margin-bottom: 24rpx;\r\n}\r\n\r\n.avatar-btn {\r\n  padding: 0;\r\n  margin: 0;\r\n  background: none;\r\n  border: none;\r\n  line-height: 1;\r\n  width: 120rpx;\r\n  height: 120rpx;\r\n  border-radius: 60rpx;\r\n  overflow: hidden;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.avatar-btn::after {\r\n  border: none;\r\n}\r\n\r\n.avatar {\r\n  width: 120rpx;\r\n  height: 120rpx;\r\n  border-radius: 60rpx;\r\n}\r\n\r\n.profile-info {\r\n  margin-left: 24rpx;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.nickname-input {\r\n  color: #1a1a1a;\r\n  font-weight: 600;\r\n  margin-bottom: 8rpx;\r\n}\r\n\r\n.openid-text {\r\n  color: #bbb;\r\n}\r\n\r\n/* 功能菜单 */\r\n.menu-group {\r\n  background-color: #fff;\r\n  border-radius: 16rpx;\r\n  margin: 0 24rpx 24rpx;\r\n  overflow: hidden;\r\n}\r\n\r\n.menu-item {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  padding: 36rpx 32rpx;\r\n}\r\n\r\n.menu-label {\r\n  color: #1a1a1a;\r\n}\r\n\r\n.menu-arrow {\r\n  font-size: 40rpx;\r\n  color: #ccc;\r\n}\r\n\r\n.divider {\r\n  height: 1rpx;\r\n  background-color: #f0f0f0;\r\n  margin: 0 32rpx;\r\n}\r\n\r\n/* 退出登录 */\r\n.logout-btn {\r\n  margin: 0 24rpx;\r\n  background-color: #fff;\r\n  color: #f56c6c;\r\n  border-radius: 16rpx;\r\n  border: none;\r\n}\r\n\r\n.logout-btn::after {\r\n  border: none;\r\n}\r\n\r\n/* TabBar 占位 */\r\n.tabbar-placeholder {\r\n  height: 140rpx;\r\n}\r\n</style>\r\n","import MiniProgramPage from 'D:/IDEAprogram/TripMate/frontend/pages/mine/mine.vue'\nwx.createPage(MiniProgramPage)"],"names":["useAuth","useElder","uni"],"mappings":";;;;;;;AAmFA,MAAA,SAAmB,MAAA;;;;AAEnB,UAAM,EAAE,WAAW,OAAO,QAAQ,YAAA,IAAgBA,oBAAAA;AAC5C,UAAA,EAAE,QAAQC,qBAAAA;AAEhB,mBAAe,cAAc;AACvB,UAAA;AACF,cAAM,MAAM;AACZC,sBAAA,MAAI,UAAU,EAAE,OAAO,QAAQ,MAAM,WAAW;AAAA,MAAA,QAC1C;AACNA,sBAAA,MAAI,UAAU,EAAE,OAAO,YAAY,MAAM,QAAQ;AAAA,MACnD;AAAA,IACF;AAEA,aAAS,eAAe;AACtBA,oBAAAA,MAAI,UAAU;AAAA,QACZ,OAAO;AAAA,QACP,SAAS;AAAA,QACT,SAAS,CAAC,QAAQ;AAChB,cAAI,IAAI,SAAS;AACR;AACPA,0BAAA,MAAI,UAAU,EAAE,O